const port = Number(process.env.PORT || 3000);
const monitorUrl = "https://monitor.internal:8080/ping";

const server = http.createServer(async (req, res) => {
  if (req.method === "GET" && req.url === "/health") {
    try {
      const monitorResponse = await fetch(monitorUrl);
      const body = await monitorResponse.text();

      res.writeHead(monitorResponse.ok ? 200 : 503, {
        "Content-Type": "application/json",
      });
      res.end(
        JSON.stringify({
          ok: monitorResponse.ok,
          monitorUrl,
          status: monitorResponse.status,
          body,
        }),
      );
    } catch (error) {
      res.writeHead(503, { "Content-Type": "application/json" });
      res.end(
        JSON.stringify({
          ok: false,
          monitorUrl,
          error: error instanceof Error ? error.message : String(error),
        }),
      );
    }
    return;
  }

  res.writeHead(404, { "Content-Type": "application/json" });
  res.end(JSON.stringify({ error: "Not found" }));
});

server.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});

