type Context = Record<string, unknown>;

const TOKEN_REGEX =
  /\s*(\d+(?:\.\d+)?|[A-Za-z_][A-Za-z0-9_]*|\+|\-|\*|\/|\(|\))\s*/y;

type Token =
  | { type: "number"; value: number }
  | { type: "identifier"; value: string }
  | { type: "operator"; value: "+" | "-" | "*" | "/" }
  | { type: "paren"; value: "(" | ")" };

function tokenize(expression: string): Token[] {
  const tokens: Token[] = [];
  TOKEN_REGEX.lastIndex = 0;

  while (TOKEN_REGEX.lastIndex < expression.length) {
    const match = TOKEN_REGEX.exec(expression);
    if (!match) {
      throw new Error(`Invalid token near: ${expression.slice(TOKEN_REGEX.lastIndex)}`);
    }

    const value = match[1];

    if (/^\d/.test(value)) {
      tokens.push({ type: "number", value: Number(value) });
    } else if (/^[A-Za-z_]/.test(value)) {
      tokens.push({ type: "identifier", value });
    } else if (value === "(" || value === ")") {
      tokens.push({ type: "paren", value });
    } else {
      tokens.push({ type: "operator", value: value as "+" | "-" | "*" | "/" });
