function evaluateTemplateFormula(template, data) {
  const match = template.match(/^{{\s*(.*?)\s*}}$/);
  if (!match) {
    throw new Error("Invalid template formula");
  }

  const expr = match[1];
  const tokens = tokenize(expr);
  let pos = 0;

  function peek() {
    return tokens[pos];
  }

  function consume(type, value) {
    const token = tokens[pos];
    if (!token || token.type !== type || (value !== undefined && token.value !== value)) {
      throw new Error(`Unexpected token: ${token ? token.value : "EOF"}`);
    }
    pos++;
    return token;
  }

  function parseExpression() {
    let value = parseTerm();
    while (peek() && peek().type === "op" && (peek().value === "+" || peek().value === "-")) {
      const op = consume("op").value;
      const rhs = parseTerm();
      value = op === "+" ? value + rhs : value - rhs;
    }
    return value;
  }

  function parseTerm() {
    let value = parseFactor();
    while (peek() && peek().type === "op" && (peek().value === "*" || peek().value === "/")) {
      const op = consume("op").value;
      const rhs = parseFactor();
      value = op === "*" ? value * rhs : value / rhs;
    }
    return value;
  }

  function parseFactor() {
    const token = peek();
    if (!token) {
      throw new Error("Unexpected end of expression");
    }

    if (token.type === "number") {
      consume("number");
      return token.value;
    }

    if (token.type === "identifier") {
      consume("identifier");
      if (!(token.value in data)) {
        throw new Error(`Unknown field: ${token.value}`);
      }
      const value = data[token.value];
      if (typeof value !== "number") {
        throw new Error(`Field must be numeric: ${token.value}`);
      }
      return value;
    }

    if (token.type === "paren" && token.value === "(") {
      consume("paren", "(");
      const value = parseExpression();
      consume("paren", ")");
      return value;
    }

    throw new Error(`Unexpected token: ${token.value}`);
  }

  const result = parseExpression();
  if (pos !== tokens.length) {
    throw new Error("Unexpected trailing tokens");
  }
  return result;
